blocks.code:
// Texto simples:
Text("Bom dia")

// Texto com modificadores encadeados:
Text("Título")
    .font(.title)
    .fontWeight(.bold)
    .foregroundStyle(.blue)

// Interpolação de tipos — formatação automática e localizada:
let preco: Double = 49.90
let data = Date.now

Text(preco, format: .currency(code: "BRL"))  // "R$ 49,90"
Text(data, format: .dateTime.day().month().year())  // "1 de abr. de 2026"

// AttributedString — formatação inline:
var atribuido = AttributedString("Texto em negrito")
atribuido[atribuido.range(of: "negrito")!].font = .bold
Text(atribuido)

// Button básico:
Button("Salvar") {
    salvarDados()
}

// Button com label customizado:
Button {
    favoritar(item)
} label: {
    Label("Favoritar", systemImage: "heart")
}

// Button com estilo:
Button("Confirmar") {
    confirmar()
}
.buttonStyle(.borderedProminent)

// Button desabilitado condicionalmente:
Button("Enviar") { enviar() }
    .disabled(formulario.isEmpty)

struct FormularioLogin: View {
    @State private var email = ""
    @State private var senha = ""

    var body: some View {
        VStack(spacing: 16) {
            TextField("Email", text: $email)
                .keyboardType(.emailAddress)      // teclado com @
                .textInputAutocapitalization(.never)
                .autocorrectionDisabled()

            SecureField("Senha", text: $senha)    // texto mascarado

            Button("Entrar") { fazerLogin() }
                .disabled(email.isEmpty || senha.isEmpty)
        }
        .padding()
        .textFieldStyle(.roundedBorder)
    }
}

// DIFÍCIL de manter — tudo num body:
struct TarefaView: View {
    let tarefa: Tarefa

    var body: some View {
        HStack {
            Image(systemName: tarefa.concluida ? "checkmark.circle.fill" : "circle")
                .foregroundStyle(tarefa.concluida ? .green : .secondary)
                .font(.title2)
            VStack(alignment: .leading, spacing: 4) {
                Text(tarefa.titulo)
                    .font(.headline)
                    .strikethrough(tarefa.concluida)
                if let prazo = tarefa.prazo {
                    Text(prazo, format: .dateTime.day().month())
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            }
            Spacer()
        }
    }
}

// MAIS FÁCIL — componentes nomeados:
struct TarefaView: View {
    let tarefa: Tarefa

    var body: some View {
        HStack {
            StatusIcon(concluida: tarefa.concluida)
            TarefaTexto(tarefa: tarefa)
            Spacer()
        }
    }
}

struct TarefaView: View {
    let tarefa: Tarefa
    @State private var expandida = false

    // Propriedade computada — sem estado próprio:
    private var cabecalho: some View {
        Text(tarefa.titulo)
            .font(.headline)
            .foregroundStyle(tarefa.concluida ? .secondary : .primary)
    }

    var body: some View {
        VStack(alignment: .leading) {
            cabecalho  // sem ()
            if expandida {
                DetalheTarefa(tarefa: tarefa)  // substruct separada
            }
        }
        .onTapGesture { expandida.toggle() }
    }
}

// Substruct privada — pode ter @State próprio:
private struct DetalheTarefa: View {
    let tarefa: Tarefa
    @State private var notasExpandidas = false  // estado próprio

    var body: some View {
        Text(tarefa.notas ?? "Sem notas")
    }
}

// Componente reutilizável com conteúdo genérico:
struct Card<Content: View>: View {
    let titulo: String
    @ViewBuilder let conteudo: () -> Content  // qualquer View

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text(titulo)
                .font(.headline)
            Divider()
            conteudo()  // renderiza o que foi passado
        }
        .padding()
        .background(.secondarySystemBackground)
        .clipShape(RoundedRectangle(cornerRadius: 12))
    }
}

// Usando o Card com conteúdo diferente em cada lugar:
Card(titulo: "Resumo") {
    Text("Três tarefas pendentes")
    Text("Duas concluídas hoje")
}

Card(titulo: "Estatísticas") {
    HStack {
        Text("Total")
        Spacer()
        Text("\(total)")
    }
}

// List — tabela nativa com todas as interações:
List(tarefas) { tarefa in
    TarefaView(tarefa: tarefa)
}
.listStyle(.insetGrouped)

// List com swipe actions:
List {
    ForEach(tarefas) { tarefa in
        TarefaView(tarefa: tarefa)
            .swipeActions(edge: .trailing) {
                Button("Deletar", role: .destructive) {
                    deletar(tarefa)
                }
            }
    }
    .onDelete(perform: deletarIndexes)  // suporte a edit mode
    .onMove(perform: moverIndexes)
}

// ForEach dentro de VStack — sem scroll automático:
ScrollView {
    VStack(spacing: 8) {
        ForEach(secoes) { secao in
            SecaoCard(secao: secao)
        }
    }
}
